const functions = require('firebase-functions');
const nodemailer = require('nodemailer');
const sgMail = require('@sendgrid/mail');
const twilio = require('twilio');

// SendGrid credentials
const SENDGRID_API_KEY = 'YOUR_SENDGRID_API_KEY';
sgMail.setApiKey(SENDGRID_API_KEY);

// Twilio credentials
const TWILIO_ACCOUNT_SID = 'YOUR_TWILIO_ACCOUNT_SID';
const TWILIO_AUTH_TOKEN = 'YOUR_TWILIO_AUTH_TOKEN';
const TWILIO_PHONE_NUMBER = 'YOUR_TWILIO_PHONE_NUMBER';

const twilioClient = new twilio(TWILIO_ACCOUNT_SID, TWILIO_AUTH_TOKEN);

// Email transporter
const transporter = nodemailer.createTransport({
  host: 'smtp.sendgrid.net',
  port: 587,
  auth: {
    user: 'apikey',
    pass: SENDGRID_API_KEY
  }
});

exports.sendMessage = functions.https.onCall((data, context) => {
  const { recipientEmail, recipientPhone } = data;
  const message = data.message;

  // Send email using SendGrid
  const mailOptions = {
    from: 'your-email@example.com',
    to: recipientEmail,
    subject: 'Message from your application',
    text: message
  };

  transporter.sendMail(mailOptions, (error, info) => {
    if (error) {
      console.error(error);
      throw error;
    }
    console.log('Email sent successfully');
  });

  // Send SMS using Twilio
  const smsOptions = {
    from: TWILIO_PHONE_NUMBER,
    to: recipientPhone,
    body: message
  };

  twilioClient.messages.create(smsOptions, (error, message) => {
    if (error) {
      console.error(error);
      throw error;
    }
    console.log('SMS sent successfully');
  });

  return { success: true };
});